sql:
SELECT warehouse_name, current_occupancy
FROM warehouses
ORDER BY current_occupancy DESC;

external_knowledge:
- top-selling metal sheets: refers to the metal sheets with the highest total revenue; 
- shipped or delivered in 2023: means the order status is either 'shipped' or 'delivered' and the order date is within the year 2023; 
- product details: include product ID and finish; 
- sales performance: includes total quantity sold, total revenue, average selling price, and the number of orders.

sql:
SELECT SUM(i.quantity * p.selling_price) AS total_inventory_value
FROM inventory i
JOIN products p ON i.product_id = p.product_id;
